import requests
import os


class Tools:
    @staticmethod
    def run(paper_id: str, action: str = "graph") -> dict:
        """
        Fetch from Connected Papers API.
        paper_id: DOI, arXiv ID, Semantic Scholar ID, etc.
        action: "graph" (default), "prior", "derivative"
        """
        api_key = os.environ.get("CONNECTED_PAPERS_API_KEY")
        if not api_key:
            return {"error": "CONNECTED_PAPERS_API_KEY not found"}

        url = f"https://api.connectedpapers.com/v1/paper/{paper_id}/{action}"

        headers = {"x-api-key": api_key}

        try:
            r = requests.get(url, headers=headers, timeout=15)
            r.raise_for_status()
            return r.json()
        except Exception as e:
            return {"error": str(e)}
